import{_ as t,o as r,c as a,a3 as s}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"How Retail Media Works - getinside","description":"Understand the getinside retail media ecosystem. From trust transfer to contextual matching, discover the 3 levers of monetization.","frontmatter":{"title":"How Retail Media Works - getinside","description":"Understand the getinside retail media ecosystem. From trust transfer to contextual matching, discover the 3 levers of monetization.","keywords":["retail media","contextual matching","endorsed advertising","parcel monetization","affiliate platform","trust transfer","getinside","e-commerce growth"],"image":"/images/gi-keyvisual.svg"},"headers":[],"relativePath":"en/start-here/why-it-works.md","filePath":"en/start-here/why-it-works.md"}'),o={name:"en/start-here/why-it-works.md"};function i(n,e,d,c,l,g){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="how-does-it-work-the-getinside-retail-media-ecosystem" tabindex="-1">How does it work? The getinside Retail Media Ecosystem <a class="header-anchor" href="#how-does-it-work-the-getinside-retail-media-ecosystem" aria-label="Permalink to &quot;How does it work? The getinside Retail Media Ecosystem&quot;">​</a></h1><p>Understand the operational functioning of <strong>getinside</strong>, the retail media platform that creates a virtuous cycle between <strong>monetization</strong> (for retailers) and <strong>qualified acquisition</strong> (for advertisers).</p><p><strong>getinside</strong> uses <strong>contextual matching</strong> — the intelligent placement of complementary offers to consumers at the exact moment they are most receptive — to create endorsed campaigns (recommended by the retailer) with <strong>conversion rates up to 5x higher</strong> than traditional display.</p><table tabindex="0"><thead><tr><th>Actor</th><th>Action</th><th>Flow</th></tr></thead><tbody><tr><td>📦 <strong>E-retailer</strong></td><td>Sends its parcels and emails to its customers</td><td>Available inventory</td></tr><tr><td>⚡ <strong>Platform</strong></td><td>Connects inventory to partner brands</td><td>Contextual matching</td></tr><tr><td>📢 <strong>Advertiser</strong></td><td>Buys this space to broadcast its offer</td><td>Distributed campaigns</td></tr><tr><td>💰 <strong>Reinvestment</strong></td><td>Earnings fund your own acquisition</td><td>Self-funded growth</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">The Virtuous Cycle</p><p>The e-retailer monetizes its parcels and emails, receives immediately accessible revenue via its Wallet, then reinvests it to acquire its own audience from complementary partners. A closed cycle that transforms cost centers into growth engines.</p></div><h2 id="trust-transfer-endorsement" tabindex="-1">Trust Transfer (Endorsement) <a class="header-anchor" href="#trust-transfer-endorsement" aria-label="Permalink to &quot;Trust Transfer (Endorsement)&quot;">​</a></h2><p>The common thread between a parcel, a newsletter, and a brand&#39;s social post:</p><ul><li><strong>Customer Relationship:</strong> The consumer has already purchased or voluntarily subscribed.</li><li><strong>Credibility:</strong> They trust the retailer (the e-retailer).</li><li><strong>Attention:</strong> They expect this content (order tracking, news).</li></ul><div class="tip custom-block"><p class="custom-block-title">The Halo Effect</p><p>By inserting yourself into this ecosystem, your brand instantly benefits from this trust capital. You are no longer an intruder, you are a <strong>recommended partner</strong>.</p><p>The <strong>Dedicated Emailing</strong> format pushes this effect to the maximum: the retailer themself writes the message in the 1st person (&quot;Dear customers, here is our favorite...&quot;), transforming the partner brand into a natural extension of their recommendations.</p></div><h2 id="for-the-e-retailer-the-economic-logic" tabindex="-1">For the E-retailer: The economic logic <a class="header-anchor" href="#for-the-e-retailer-the-economic-logic" aria-label="Permalink to &quot;For the E-retailer: The economic logic&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">The virtuous circle of Reinvestment</p><p>getinside is not just an ad network, it&#39;s a growth accelerator. These revenues contribute directly to your <strong>EBITDA</strong>, with <strong>net margins of 65-70%</strong> that reflect the efficiency of your existing logistics assets.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>1. Monetization</strong><p>Your parcels and emails generate cash thanks to third-party advertisers.</p></div><div class="gi-value-card"><strong>2. Instant Transfer</strong><p>Your earnings are available on your Wallet. No need to wait for a bank transfer.</p></div><div class="gi-value-card"><strong>3. Acquisition</strong><p>You reinvest this budget to broadcast YOUR campaigns to complementary partners.</p></div></div><p><em>Result: You finance your customer acquisition... thanks to your own parcels!</em></p></div><h2 id="_3-levers-1-ecosystem" tabindex="-1">3 Levers, 1 Ecosystem <a class="header-anchor" href="#_3-levers-1-ecosystem" aria-label="Permalink to &quot;3 Levers, 1 Ecosystem&quot;">​</a></h2><p>Leave no asset unexploited. getinside values your physical and digital touchpoints to maximize coverage.</p><table tabindex="0"><thead><tr><th>Lever</th><th>Key Strength</th><th>Strategic Role</th></tr></thead><tbody><tr><td>📦 <strong>Parcel Insert</strong></td><td><strong>100% attention</strong> — hyper-concentration of the consumer during unboxing</td><td>Memory anchoring, physical handling, maximum conversion</td></tr><tr><td>📧 <strong>Dedicated Emailing</strong></td><td><strong>Volume &amp; Responsiveness</strong></td><td>Immediate traffic, &quot;Flash&quot; offers, behavioral targeting</td></tr><tr><td>📱 <strong>Social Ads</strong></td><td><strong>Virality &amp; Data</strong></td><td>Brand awareness, social proof, youth recruitment</td></tr></tbody></table><h2 id="getinside-expertise-your-accelerator" tabindex="-1">getinside Expertise: Your Accelerator <a class="header-anchor" href="#getinside-expertise-your-accelerator" aria-label="Permalink to &quot;getinside Expertise: Your Accelerator&quot;">​</a></h2><p>Retail Media is powerful, but complex to operate alone.</p><table tabindex="0"><thead><tr><th>🚫 Without getinside</th><th>✅ With getinside</th></tr></thead><tbody><tr><td>Negotiating with 50 sites one by one.</td><td>A single point of contact.</td></tr><tr><td>Managing 50 invoices and contracts.</td><td>A single centralized invoice.</td></tr><tr><td>Print quality risk.</td><td>Certified logistics and CSR process.</td></tr><tr><td>No format standardization.</td><td>Standardized tracking.</td></tr><tr><td>Scattered reporting.</td><td>Strategic advice included.</td></tr></tbody></table><h2 id="quality-as-a-growth-engine" tabindex="-1">Quality as a Growth Engine <a class="header-anchor" href="#quality-as-a-growth-engine" aria-label="Permalink to &quot;Quality as a Growth Engine&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">⭐ The Distributor Score: Your access key</p><p>Each partner e-retailer receives a <strong>Distributor Score</strong> (1-5 stars) based on <strong>7 key criteria</strong>: adherence to deadlines, tracking quality, error rate, GDPR compliance, complaint rate, API integration, and responsiveness.</p><p>This score determines your <strong>visibility in the platform&#39;s search engine</strong> and your priority access to premium campaigns. Excellent execution strengthens this score, builds lasting trust with advertisers, and opens doors to growing revenue opportunities.</p></div><h2 id="contextual-matching-relevance-above-all" tabindex="-1">Contextual Matching: Relevance above all <a class="header-anchor" href="#contextual-matching-relevance-above-all" aria-label="Permalink to &quot;Contextual Matching: Relevance above all&quot;">​</a></h2><p>The power of getinside lies in its <strong>contextual consistency</strong>. We offer <strong>complementary offers</strong> at the exact moment the consumer needs them.</p><div class="gi-value-grid"><div class="gi-value-card"><span>🍷 <strong>The Epicurean</strong> (Newsletter)</span><p>Trigger: Purchase of aged cheese.</p><p>➔ Offer pushed: A box of selected wines.</p></div><div class="gi-value-card"><span>🏃 <strong>The Athlete</strong> (Social Ads)</span><p>Trigger: Follower of a running equipment brand.</p><p>➔ Offer pushed: Nutrition &amp; recovery program.</p></div><div class="gi-value-card"><span>👶 <strong>Young Parents</strong> (Parcel Insert)</span><p>Trigger: Order of early learning toys.</p><p>➔ Offer pushed: Organic clothing for kids.</p></div><div class="gi-value-card"><span>🪴 <strong>Home Sweet Home</strong> (Parcel Insert)</span><p>Trigger: Purchase of linen bed sheets.</p><p>➔ Offer pushed: Fresh flowers subscription.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Ready to activate your growth?</p><p>Whether you are an advertiser looking for new customers or an e-retailer wanting to monetize your parcels, the getinside ecosystem is designed for you.</p><p><a href="mailto:studio@getinside.com" target="_blank" rel="noreferrer">Discuss my project</a></p></div>',23)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
